ionoscloud:alb/balancer:Balancer.description:
Manages an [Application Load Balancer](https://docs.ionos.com/cloud/network-services/application-load-balancer/overview) on IONOS CLOUD.

## Example Usage

<!--Start PulumiCodeChooser -->
```typescript
import * as pulumi from "@pulumi/pulumi";
import * as ionoscloud from "@ionos-cloud/sdk-pulumi";

const example = new ionoscloud.compute.Datacenter("example", {
    name: "Datacenter Example",
    location: "us/las",
    description: "datacenter description",
    secAuthProtection: false,
});
const example1 = new ionoscloud.compute.Lan("example_1", {
    datacenterId: example.id,
    "public": true,
    name: "Lan Example",
});
const example2 = new ionoscloud.compute.Lan("example_2", {
    datacenterId: example.id,
    "public": true,
    name: "Lan Example",
});
const exampleBalancer = new ionoscloud.alb.Balancer("example", {
    datacenterId: example.id,
    name: "ALB Example",
    listenerLan: example1.id.apply(x =>Number(x)),
    ips: ["10.12.118.224"],
    targetLan: example2.id.apply(x =>Number(x)),
    lbPrivateIps: ["10.13.72.225/24"],
    centralLogging: true,
    loggingFormat: "%{+Q}o %{-Q}ci - - [%trg] %r %ST %B \"\" \"\" %cp %ms %ft %b %s %TR %Tw %Tc %Tr %Ta %tsc %ac %fc %bc %sc %rc %sq %bq %CC %CS %hrl %hsl",
});
```
