ionoscloud:alb/forwardingRule:Forwarding.description:
Manages an **Application Load Balancer Forwarding Rule** on IONOS CLOUD.

## Example Usage

<!--Start PulumiCodeChooser -->
```typescript
import * as pulumi from "@pulumi/pulumi";
import * as ionoscloud from "@ionos-cloud/sdk-pulumi";
import * as std from "@pulumi/std";

const example = new ionoscloud.compute.Datacenter("example", {
    name: "Datacenter Example",
    location: "us/las",
    description: "datacenter description",
    secAuthProtection: false,
});
const example1 = new ionoscloud.compute.Lan("example_1", {
    datacenterId: example.id,
    "public": true,
    name: "Lan Example",
});
const example2 = new ionoscloud.compute.Lan("example_2", {
    datacenterId: example.id,
    "public": true,
    name: "Lan Example",
});
const exampleBalancer = new ionoscloud.alb.Balancer("example", {
    datacenterId: example.id,
    name: "ALB Example",
    listenerLan: example1.id.apply(x =>Number(x)),
    ips: ["10.12.118.224"],
    targetLan: example2.id.apply(x =>Number(x)),
    lbPrivateIps: ["10.13.72.225/24"],
});
//optionally you can add a certificate to the application load balancer
const cert = new ionoscloud.cert.Certificate("cert", {
    name: "add_name_here",
    certificate: std.file({
        input: "path_to_cert",
    }).result,
    certificateChain: std.file({
        input: "path_to_cert_chain",
    }).result,
    privateKey: std.file({
        input: "path_to_private_key",
    }).result,
});
const exampleForwardingRule = new ionoscloud.alb.ForwardingRule("example", {
    datacenterId: example.id,
    applicationLoadbalancerId: exampleBalancer.id,
    name: "ALB FR Example",
    protocol: "HTTP",
    listenerIp: "10.12.118.224",
    listenerPort: 8080,
    clientTimeout: 1000,
    httpRules: [
        {
            name: "http_rule",
            type: "REDIRECT",
            dropQuery: true,
            location: "www.ionos.com",
            statusCode: 301,
            conditions: [{
                type: "HEADER",
                condition: "EQUALS",
                negate: true,
                key: "key",
                value: "10.12.120.224/24",
            }],
        },
        {
            name: "http_rule_2",
            type: "STATIC",
            dropQuery: false,
            statusCode: 303,
            responseMessage: "Response",
            contentType: "text/plain",
            conditions: [{
                type: "QUERY",
                condition: "MATCHES",
                negate: false,
                key: "key",
                value: "10.12.120.224/24",
            }],
        },
    ],
    serverCertificates: [cert.id],
});
